#pragma OPENCL EXTENSION cl_khr_fp64 : enable

#define REC_LENGTH 49
#define LATITUDE_POS 28

__kernel void compute_distances(
    __global const char* sandbox,
    __global float* z,
    const float target_lat,
    const float target_long,
    const int rec_count)
{
    int i = get_global_id(0);
    if (i >= rec_count) return;

    const int base_idx = i * REC_LENGTH + LATITUDE_POS - 1;

    // Each latitude and longitude are in ASCII form, convert them to floats
    // Latitude is at rec_iter, longitude is at rec_iter + 5
    // We convert ASCII to float manually here since OpenCL C does not have atof.
    // However, here we assume the floats are in fixed format with 5 characters each.
    // To keep behavior consistent, we parse as floats using a helper function.

    // A helper function to parse float from ASCII substring of length n
    // We assume the format is consistent.

    // But since OpenCL C does not support string parsing functions, and the input format is fixed-width,
    // we implement a simple parser for the float format used.
    // The input format for lat and long is assumed to be 5 chars each, e.g. " 35.4" or "-12.3"

    // We'll read 5 characters and parse to float

    char lat_str[6];
    char long_str[6];
    for (int c = 0; c < 5; c++) {
        lat_str[c] = sandbox[base_idx + c];
        long_str[c] = sandbox[base_idx + 5 + c];
    }
    lat_str[5] = '\0';
    long_str[5] = '\0';

    // Convert lat_str and long_str to float
    // Simple atof implementation for this fixed format - handle optional space, optional sign, digits, decimal point, digits

    float tmp_lat = 0.f;
    float tmp_long = 0.f;

    // Parsing function
    // return parsed float, assuming format "[-| ]ddd.d"
    float parse_float(const char *s) {
        float result = 0.f;
        int sign = 1;
        int i = 0;
        // skip spaces
        while (s[i] == ' ') i++;
        if (s[i] == '-') {
            sign = -1;
            i++;
        }
        // integer part
        while (s[i] >= '0' && s[i] <= '9') {
            result = result * 10.f + (s[i] - '0');
            i++;
        }
        // fraction
        if (s[i] == '.') {
            i++;
            float frac = 0.f;
            float base = 0.1f;
            while (s[i] >= '0' && s[i] <= '9') {
                frac += base * (s[i] - '0');
                base *= 0.1f;
                i++;
            }
            result += frac;
        }
        return sign * result;
    }

    tmp_lat = parse_float(lat_str);
    tmp_long = parse_float(long_str);

    float dlat = tmp_lat - target_lat;
    float dlong = tmp_long - target_long;
    z[i] = sqrt(dlat * dlat + dlong * dlong);
}
